import { configureStore } from "@reduxjs/toolkit";
import { trendReducer } from "./StoreSlices";
import { cookieReducer } from "./StoreSlices";

const ReduxStore=configureStore({
    reducer:{
        movies:trendReducer,
        cookie:cookieReducer,
    }
})

export default ReduxStore;
